/*
  Santa's Castle Global Framework Styles
  -------------------------------------
  Visual style based on provided red bokeh hero with clean, editorial typography.
*/

/* Design System Tokens ----------------------------------------------------- */
:root {
  /* Primary reds */
  --color-primary-700: #B01927; /* Deep crimson */
  --color-primary-500: #E53935; /* Vivid festive red */

  /* Secondary / supporting */
  --color-secondary-600: #CC3B3B;
  --color-secondary-100: #F2D7DC;

  /* Neutrals */
  --color-neutral-0: #FFFFFF;
  --color-neutral-50: #F5F5F5;
  --color-neutral-800: #333333;
  --color-neutral-600: #777777;

  /* Semantic */
  --color-success: #2E7D32;
  --color-error: #C62828;
  --color-warning: #F9A825;
  --color-info: #1565C0;

  /* Typography */
  --font-heading: 'Raleway', Helvetica, sans-serif;
  --font-body: 'Source Sans 3', Arial, sans-serif;
  --font-code: 'Source Code Pro', monospace;

  --font-size-h1: 3.25rem; /* ~52px */
  --font-size-h2: 2rem;    /* 32px */
  --font-size-h3: 1.5rem;  /* 24px */
  --font-size-body: 1rem;  /* 16px */
  --font-size-small: 0.8125rem; /* 13px */

  --line-height-tight: 1.2;
  --line-height-normal: 1.5;
  --line-height-relaxed: 1.7;

  /* Spacing scale (8px base) */
  --space-1: 4px;
  --space-2: 8px;
  --space-3: 16px;
  --space-4: 24px;
  --space-5: 32px;
  --space-6: 48px;
  --space-7: 64px;

  /* Layout */
  --layout-max-width: 1120px;
  --radius-sm: 4px;
  --radius-md: 6px;
  --shadow-soft: 0 12px 30px rgba(0, 0, 0, 0.12);
}

/* Global Resets & Base Styles --------------------------------------------- */
* {
  box-sizing: border-box;
}

html {
  font-size: 16px;
}

body {
  margin: 0;
  font-family: var(--font-body);
  font-size: var(--font-size-body);
  line-height: var(--line-height-normal);
  color: var(--color-neutral-800);
  background-color: var(--color-neutral-50);
}

img {
  max-width: 100%;
  height: auto;
  display: block;
}

a {
  color: var(--color-primary-700);
  text-decoration: none;
}

a:hover,
a:focus-visible {
  text-decoration: underline;
}

h1, h2, h3, h4, h5, h6 {
  margin: 0 0 var(--space-3);
  font-family: var(--font-heading);
  font-weight: 300;
  letter-spacing: 0.03em;
}

h1 {
  font-size: var(--font-size-h1);
  line-height: var(--line-height-tight);
}

h2 {
  font-size: var(--font-size-h2);
}

h3 {
  font-size: var(--font-size-h3);
}

p {
  margin: 0 0 var(--space-3);
}

ul, ol {
  margin: 0;
  padding: 0;
}

.site-shell {
  min-height: 100vh;
}

.container {
  width: 100%;
  max-width: var(--layout-max-width);
  margin: 0 auto;
  padding-inline: var(--space-4);
}

.visually-hidden {
  position: absolute;
  width: 1px;
  height: 1px;
  padding: 0;
  margin: -1px;
  overflow: hidden;
  clip: rect(0, 0, 0, 0);
  white-space: nowrap;
  border: 0;
}

/* Header ------------------------------------------------------------------ */
.site-header {
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  z-index: 20;
  color: var(--color-neutral-0);
  font-family: var(--font-heading);
}

.header-inner {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding-block: var(--space-3);
}

.brand {
  display: inline-flex;
  align-items: center;
  gap: var(--space-2);
  color: var(--color-neutral-0);
  text-decoration: none;
}

.brand-mark {
  width: 40px;
  height: 40px;
  border-radius: 999px;
  background: rgba(255, 255, 255, 0.18);
  border: 2px solid rgba(255, 255, 255, 0.85);
  display: inline-flex;
  align-items: center;
  justify-content: center;
  font-size: 0.75rem;
  font-weight: 600;
  letter-spacing: 0.12em;
  text-transform: uppercase;
}

.brand-text {
  display: flex;
  flex-direction: column;
}

.brand-title {
  font-size: 1.125rem;
  letter-spacing: 0.12em;
  text-transform: uppercase;
  font-weight: 400;
}

.brand-subtitle {
  font-size: 0.6875rem;
  letter-spacing: 0.16em;
  text-transform: uppercase;
  opacity: 0.8;
}

.site-nav {
  font-size: 0.875rem;
}

.nav-list {
  list-style: none;
  display: flex;
  align-items: center;
  gap: var(--space-4);
}

.nav-item a {
  color: var(--color-neutral-0);
  text-decoration: none;
  text-transform: none;
  letter-spacing: 0.12em;
  font-weight: 400;
  white-space: nowrap;
  position: relative;
  padding-block: 4px;
}

.nav-item a::after {
  content: "";
  position: absolute;
  left: 0;
  bottom: 0;
  width: 0;
  height: 2px;
  background-color: rgba(255, 255, 255, 0.85);
  transition: width 160ms ease-out;
}

.nav-item a:hover::after,
.nav-item a:focus-visible::after,
.nav-item a[aria-current="page"]::after {
  width: 100%;
}

.nav-item--cart a {
  font-weight: 600;
}

/* Hero -------------------------------------------------------------------- */
.site-hero {
  position: relative;
  padding: 120px 0 96px;
  color: var(--color-neutral-0);
  text-align: center;
  overflow: hidden;

  /* Layered bokeh-inspired background */
  background-image:
    radial-gradient(circle at 15% 20%, rgba(255, 255, 255, 0.38) 0, rgba(255, 255, 255, 0) 40%),
    radial-gradient(circle at 70% 25%, rgba(255, 255, 255, 0.32) 0, rgba(255, 255, 255, 0) 45%),
    radial-gradient(circle at 30% 80%, rgba(255, 255, 255, 0.25) 0, rgba(255, 255, 255, 0) 46%),
    radial-gradient(circle at 85% 80%, rgba(255, 255, 255, 0.22) 0, rgba(255, 255, 255, 0) 40%),
    linear-gradient(135deg, var(--color-primary-700) 0%, var(--color-primary-500) 60%, var(--color-primary-700) 100%);
}

.site-hero::before {
  /* Subtle starburst overlay */
  content: "";
  position: absolute;
  inset: 0;
  background-image:
    radial-gradient(circle at 20% 40%, rgba(255, 255, 255, 0.1) 0, rgba(255, 255, 255, 0) 35%),
    radial-gradient(circle at 60% 55%, rgba(255, 255, 255, 0.08) 0, rgba(255, 255, 255, 0) 35%);
  pointer-events: none;
}

.hero-inner {
  position: relative;
  z-index: 1;
}

/* Main Content Card ------------------------------------------------------- */
.site-content {
  position: relative;
  z-index: 2;
  margin-top: -48px; /* Pull content up over hero bottom edge */
  margin-bottom: var(--space-7);
  padding: var(--space-6) var(--space-5) var(--space-7);
  background-color: var(--color-neutral-0);
  border-radius: var(--radius-sm);
  box-shadow: var(--shadow-soft);
}

/* Footer ------------------------------------------------------------------ */
.site-footer {
  background: linear-gradient(180deg, #3a0f16 0%, #22070b 100%);
  color: var(--color-secondary-100);
}

.footer-inner {
  display: flex;
  flex-wrap: wrap;
  gap: var(--space-5);
  padding-block: var(--space-6);
}

.footer-branding {
  flex: 1 1 260px;
  display: flex;
  align-items: flex-start;
  gap: var(--space-3);
}

.brand-mark--footer {
  width: 44px;
  height: 44px;
  border-color: rgba(255, 255, 255, 0.9);
  background: rgba(255, 255, 255, 0.12);
}

.footer-brand-text {
  max-width: 320px;
}

.footer-title {
  font-family: var(--font-heading);
  font-size: 1.125rem;
  letter-spacing: 0.12em;
  text-transform: uppercase;
  margin: 0 0 var(--space-2);
}

.footer-tagline {
  margin: 0;
  font-size: 0.875rem;
  color: rgba(255, 255, 255, 0.78);
}

.footer-nav {
  flex: 2 1 420px;
  display: flex;
  flex-wrap: wrap;
  gap: var(--space-5);
}

.footer-column {
  min-width: 160px;
}

.footer-heading {
  font-size: 0.875rem;
  font-family: var(--font-heading);
  letter-spacing: 0.18em;
  text-transform: uppercase;
  margin-bottom: var(--space-3);
  color: rgba(255, 255, 255, 0.9);
}

.footer-links {
  list-style: none;
}

.footer-links li + li {
  margin-top: var(--space-2);
}

.footer-links a {
  font-size: 0.875rem;
  color: rgba(255, 255, 255, 0.8);
  text-decoration: none;
}

.footer-links a:hover,
.footer-links a:focus-visible {
  color: var(--color-neutral-0);
  text-decoration: underline;
}

.footer-bottom {
  border-top: 1px solid rgba(255, 255, 255, 0.12);
  padding-block: var(--space-3);
}

.footer-bottom-inner {
  display: flex;
  align-items: center;
  justify-content: space-between;
}

.footer-meta {
  margin: 0;
  font-size: 0.75rem;
  color: rgba(255, 255, 255, 0.7);
}

/* Utility: current year can be updated via server or script if desired */
.current-year {
  white-space: nowrap;
}

/* Responsive Adjustments -------------------------------------------------- */
@media (max-width: 960px) {
  .header-inner {
    gap: var(--space-3);
  }

  .nav-list {
    gap: var(--space-3);
    font-size: 0.8125rem;
  }

  .site-content {
    padding-inline: var(--space-4);
  }
}

@media (max-width: 768px) {
  .site-header {
    position: relative;
    background: linear-gradient(135deg, var(--color-primary-700) 0%, var(--color-primary-500) 100%);
  }

  .site-hero {
    padding-top: var(--space-6);
  }

  .header-inner {
    flex-direction: column;
    align-items: flex-start;
  }

  .nav-list {
    flex-wrap: wrap;
    row-gap: var(--space-2);
  }

  .site-content {
    margin-top: 0;
    border-radius: 0;
  }

  .footer-inner {
    flex-direction: column;
  }

  .footer-bottom-inner {
    flex-direction: column;
    align-items: flex-start;
    gap: var(--space-2);
  }
}

@media (max-width: 480px) {
  .container {
    padding-inline: var(--space-3);
  }

  .nav-list {
    gap: var(--space-2);
  }

  .brand-title {
    font-size: 1rem;
  }

  .site-hero {
    padding-block: var(--space-5);
  }
}
